// ============================================================================
// Tablet Device Mode — ?room=CODE&mode=tablet or auto-detected
// ============================================================================
(function() {
  var params = new URLSearchParams(window.location.search);
  var room = params.get('room');
  if (!room) return;
  if (params.get('spectator') === '1' || params.get('camera') === '1') return;

  // Tablet detection: explicit param or large touch screen joining a room
  var isTabletMode = params.get('mode') === 'tablet' ||
    (window.innerWidth >= 768 && 'ontouchstart' in window);

  if (!isTabletMode) {
    // Fall through to secondary device mode below
    buildSecondaryUI(room, params);
    return;
  }

  // === TABLET MODE ===
  isSecondaryDevice = true;
  myRoomCode = room;

  // Replace page with tablet UI
  while (document.body.firstChild) document.body.removeChild(document.body.firstChild);

  // Panel definitions
  var TABLET_PANELS = [
    { key: 'piano', label: 'Piano', defaultOn: true },
    { key: 'chat', label: 'Chat', defaultOn: true },
    { key: 'audio', label: 'Audio', defaultOn: true },
    { key: 'fingers', label: 'Fingers', defaultOn: false },
    { key: 'drills', label: 'Drills', defaultOn: false },
    { key: 'staff', label: 'Staff', defaultOn: false }
  ];

  // Load saved state from localStorage
  var savedState = {};
  try { savedState = JSON.parse(localStorage.getItem('tabletPanelState') || '{}'); } catch(e) {}
  var panelVisible = {};
  TABLET_PANELS.forEach(function(p) {
    panelVisible[p.key] = savedState.hasOwnProperty(p.key) ? savedState[p.key] : p.defaultOn;
  });

  // Load saved panel sizes
  var panelSizes = {};
  try { panelSizes = JSON.parse(localStorage.getItem('tabletPanelSizes') || '{}'); } catch(e) {}

  function savePanelState() {
    localStorage.setItem('tabletPanelState', JSON.stringify(panelVisible));
  }
  function savePanelSizes() {
    localStorage.setItem('tabletPanelSizes', JSON.stringify(panelSizes));
  }

  // --- Build tablet DOM ---
  var tabletApp = document.createElement('div');
  tabletApp.className = 'tablet-app';

  // Toolbar
  var toolbar = document.createElement('div');
  toolbar.className = 'tablet-toolbar';

  var pillContainer = document.createElement('div');
  pillContainer.className = 'tablet-pills';
  var pills = {};

  TABLET_PANELS.forEach(function(p) {
    var pill = document.createElement('button');
    pill.className = 'tablet-pill' + (panelVisible[p.key] ? ' active' : '');
    pill.textContent = p.label;
    pill.setAttribute('data-panel', p.key);
    pill.onclick = function() {
      panelVisible[p.key] = !panelVisible[p.key];
      pill.className = 'tablet-pill' + (panelVisible[p.key] ? ' active' : '');
      updateTabletLayout();
      savePanelState();
    };
    pills[p.key] = pill;
    pillContainer.appendChild(pill);
  });
  toolbar.appendChild(pillContainer);

  // Right side of toolbar: room code + status + exit
  var toolbarRight = document.createElement('div');
  toolbarRight.className = 'tablet-toolbar-right';
  var roomLabel = document.createElement('span');
  roomLabel.className = 'tablet-room';
  roomLabel.textContent = 'Room: ' + room;
  toolbarRight.appendChild(roomLabel);

  var statusSpan = document.createElement('span');
  statusSpan.className = 'tablet-status';
  statusSpan.id = 'tabletStatus';
  statusSpan.textContent = 'Connecting...';
  toolbarRight.appendChild(statusSpan);

  var speakingIndicator = document.createElement('span');
  speakingIndicator.className = 'tablet-speaking';
  speakingIndicator.id = 'tabletSpeaking';
  speakingIndicator.textContent = '';
  toolbarRight.appendChild(speakingIndicator);

  toolbar.appendChild(toolbarRight);
  tabletApp.appendChild(toolbar);

  // Panel container
  var panelContainer = document.createElement('div');
  panelContainer.className = 'tablet-panels';
  panelContainer.id = 'tabletPanelContainer';

  // --- Create each panel ---
  var panelEls = {};

  // 1. Piano panel (waterfall + keyboard)
  (function() {
    var panel = document.createElement('div');
    panel.className = 'tablet-panel';
    panel.setAttribute('data-panel', 'piano');

    var midiStack = document.createElement('div');
    midiStack.className = 'midi-stack';
    midiStack.id = 'midiStack';
    midiStack.style.flex = '1';
    midiStack.style.minHeight = '0';

    var rollWrap = document.createElement('div');
    rollWrap.className = 'roll-wrap';
    rollWrap.id = 'rollWrap';
    rollWrap.style.background = '#0a0a0a';
    rollWrap.style.overflow = 'hidden';
    var rollCanvas = document.createElement('canvas');
    rollCanvas.id = 'pianoRollCanvas';
    rollWrap.appendChild(rollCanvas);
    midiStack.appendChild(rollWrap);

    var kbWrap = document.createElement('div');
    kbWrap.className = 'keyboard-wrap';
    kbWrap.id = 'keyboardWrap';
    kbWrap.style.background = '#0a0a0a';
    var kbCanvas = document.createElement('canvas');
    kbCanvas.id = 'keyboardCanvas';
    kbWrap.appendChild(kbCanvas);
    midiStack.appendChild(kbWrap);

    panel.appendChild(midiStack);
    panelEls.piano = panel;
  })();

  // 2. Chat panel
  (function() {
    var panel = document.createElement('div');
    panel.className = 'tablet-panel';
    panel.setAttribute('data-panel', 'chat');

    var header = document.createElement('div');
    header.className = 'panel-header';
    header.innerHTML = '<div class="dot" style="background:var(--gemini)"></div>CONVERSATION';
    panel.appendChild(header);

    var chatArea = document.createElement('div');
    chatArea.className = 'chat-area';
    chatArea.id = 'chatArea';
    chatArea.style.cssText = 'flex:1;overflow-y:auto;padding:8px;display:flex;flex-direction:column;gap:6px;';
    var sysMsg = document.createElement('div');
    sysMsg.className = 'system-msg';
    sysMsg.style.cssText = 'font-size:11px;color:var(--text3);text-align:center;padding:12px;';
    sysMsg.textContent = 'Waiting for session...';
    chatArea.appendChild(sysMsg);
    panel.appendChild(chatArea);

    panelEls.chat = panel;
  })();

  // 3. Audio panel
  (function() {
    var panel = document.createElement('div');
    panel.className = 'tablet-panel';
    panel.setAttribute('data-panel', 'audio');

    var header = document.createElement('div');
    header.className = 'panel-header';
    header.innerHTML = '<div class="dot" style="background:var(--accent)"></div>AUDIO LEVEL';
    panel.appendChild(header);

    // User level
    var userMeter = document.createElement('div');
    userMeter.className = 'level-meter';
    userMeter.innerHTML = '<span style="font-size:9px;color:var(--text3);min-width:38px;">User</span>' +
      '<div class="level-bar-bg"><div class="level-bar" id="levelBar"></div></div>' +
      '<div class="level-label" id="levelLabel">0</div>';
    panel.appendChild(userMeter);

    // Gemini level
    var geminiMeter = document.createElement('div');
    geminiMeter.className = 'level-meter';
    geminiMeter.id = 'geminiSpeaking';
    geminiMeter.innerHTML = '<span style="font-size:9px;color:var(--text3);min-width:38px;">Gemini</span>' +
      '<div class="level-bar-bg"><div class="level-bar" id="geminiVolFill" style="background:var(--gemini);"></div></div>' +
      '<span id="geminiSpeakLabel" style="font-size:9px;color:var(--text3);min-width:38px;text-align:right;">Silent</span>';
    panel.appendChild(geminiMeter);

    panelEls.audio = panel;
  })();

  // 4. Fingers panel
  (function() {
    var panel = document.createElement('div');
    panel.className = 'tablet-panel';
    panel.setAttribute('data-panel', 'fingers');

    var header = document.createElement('div');
    header.className = 'panel-header';
    header.innerHTML = '<div class="dot" style="background:#c084fc"></div>FINGER TRACKING <span class="camera-badge off" id="cameraBadge">Camera Off</span>';
    panel.appendChild(header);

    var camWrap = document.createElement('div');
    camWrap.id = 'remoteCameraWrap';
    camWrap.style.cssText = 'display:none;background:#000;border-bottom:1px solid var(--border);';
    var camImg = document.createElement('img');
    camImg.id = 'remoteCameraImg';
    camImg.style.cssText = 'width:100%;display:block;';
    camImg.alt = 'Camera';
    camWrap.appendChild(camImg);
    panel.appendChild(camWrap);

    var techEntries = document.createElement('div');
    techEntries.id = 'techniqueEntries';
    techEntries.style.cssText = 'padding:8px;max-height:200px;overflow-y:auto;';
    techEntries.innerHTML = '<div style="font-size:11px;color:var(--text3);">Camera off</div>';
    panel.appendChild(techEntries);

    // Keep techniquePanel ID for existing code
    panel.id = 'techniquePanel';
    panelEls.fingers = panel;
  })();

  // 5. Drills panel
  (function() {
    var panel = document.createElement('div');
    panel.className = 'tablet-panel';
    panel.setAttribute('data-panel', 'drills');

    var header = document.createElement('div');
    header.className = 'panel-header';
    header.innerHTML = '<div class="dot" style="background:var(--green)"></div>DRILLS';
    panel.appendChild(header);

    var drillContent = document.createElement('div');
    drillContent.style.cssText = 'padding:8px;overflow-y:auto;flex:1;';
    drillContent.innerHTML =
      '<div style="font-size:10px;color:var(--text3);letter-spacing:0.05em;font-weight:700;margin-bottom:4px;">STAGE 1: SINGLE FINGER</div>' +
      '<div class="drill-card" id="drill-1-1" onclick="selectDrill(\'1-1\')">' +
        '<div class="drill-id">1-1</div><div class="drill-name">Tempo</div>' +
        '<div class="drill-desc">Play a single note at a steady tempo.</div></div>' +
      '<div class="drill-card" id="drill-1-2" onclick="selectDrill(\'1-2\')">' +
        '<div class="drill-id">1-2</div><div class="drill-name">Strength</div>' +
        '<div class="drill-desc">Play a note at a specific dynamic level.</div></div>' +
      '<div id="drillSettings" style="display:none;">' +
        '<div class="drill-settings">' +
          '<label>Note <select id="drillNote"><option value="60">C4</option><option value="62">D4</option><option value="64">E4</option><option value="65">F4</option><option value="67">G4</option></select></label>' +
          '<label>BPM <input type="number" id="drillBpm" value="80" min="40" max="200"></label>' +
          '<label id="drillDynamicLabel" style="display:none;">Dynamic <select id="drillDynamic"><option value="32">pp</option><option value="64" selected>mp</option><option value="96">f</option></select></label>' +
          '<label>Measures <input type="number" id="drillMeasures" value="8" min="2" max="32"></label>' +
        '</div>' +
        '<div class="drill-start-btn" id="drillStartBtn" onclick="startDrill()">Start Drill</div>' +
      '</div>';
    panel.appendChild(drillContent);

    panelEls.drills = panel;
  })();

  // 6. Grand Staff panel
  (function() {
    var panel = document.createElement('div');
    panel.className = 'tablet-panel';
    panel.setAttribute('data-panel', 'staff');

    var staffWrap = document.createElement('div');
    staffWrap.className = 'staff-wrap';
    staffWrap.id = 'staffWrap';
    staffWrap.style.cssText = 'flex:1;padding:0;background:#050508;overflow:hidden;min-height:0;';
    var staffCanvas = document.createElement('canvas');
    staffCanvas.id = 'grandStaffCanvas';
    staffWrap.appendChild(staffCanvas);
    panel.appendChild(staffWrap);

    panelEls.staff = panel;
  })();

  // Add all panels to container
  TABLET_PANELS.forEach(function(p) {
    panelContainer.appendChild(panelEls[p.key]);
  });
  tabletApp.appendChild(panelContainer);
  document.body.appendChild(tabletApp);

  // Hidden elements needed by global functions
  var hiddenControls = document.createElement('div');
  hiddenControls.style.display = 'none';
  hiddenControls.innerHTML =
    '<select id="midiInputSelect"></select>' +
